queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?tourist_attractions a :Tourist_Attractions .
    ?tourist_attractions p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?local_markets a :Local_Markets .
    ?local_markets p:name ?name .
    ?local_markets p:location ?location_f .
    FILTER(STR(?location_f) = "London")
    BIND(?name AS ?o0)
  }
}

